import ThemeIcon from "~/shared/folder/ThemeIcon";
import { Theme } from "~/types/settings/settings";
import { MediaMenu } from "~/types/media/media";
import Folder from "~/shared/folder/Folder";
import Status from "~/components/status";
import clsx from "clsx";
/* <fs_premium_only> */
import { useLayoutEffect, useState } from "@wordpress/element";
import useScrollFade from "~/hooks/useScrollFade";
import BlockStack from "~/components/blockStack";
/* </fs_premium_only> */

const DynamicFolders = ({
    enabled,
    menu,
    theme,
    /* <fs_premium_only> */
    onMenu,
    /* </fs_premium_only> */
    folders,
    showCount,
}: {
    enabled?: boolean;
    menu: MediaMenu;
    theme?: Theme;
    /* <fs_premium_only> */
    onMenu: (menu: MediaMenu) => void;
    /* </fs_premium_only> */
    folders: Record<string, number>;
    showCount?: boolean;
}) => {
    const active = menu === "dynamic";

    /* <fs_premium_only> */
    const [activeType, setActiveType] = useState<string>("");
    const { ref: scrollRef, showFade, checkFade } = useScrollFade();

    useLayoutEffect(() => {
        requestAnimationFrame(checkFade);
    }, [active]);

    const handleTypeClick = (key: string) => {
        setActiveType(key);

        window.pnpnmMedia?.initFilter(
            Object.entries(folders).map(([key, count]) => ({
                id: key,
                name: key,
                type: "dynamic",
            })),
        );

        window.pnpnmMedia
            ?.getFrame()
            ?.find("#pnpnm-media-folder-filter")
            ?.val(`dynamic_${key}`)
            ?.trigger("change");
    };
    /* </fs_premium_only> */

    if (!enabled) return null;

    return (
        <div className={clsx("pnpnm-dynamic-folders")}>
            <Status
                isPro={true}
                size="extrasmall"
                placement="right-center"
                right={3}
            >
                <Folder
                    name="Dynamic Folders"
                    count={
                        showCount
                            ? Object.keys(folders || {}).length
                            : undefined
                    }
                    icon={
                        <ThemeIcon
                            theme={theme}
                            active={active}
                            open={active}
                        />
                    }
                    active={active}
                    open={active}
                    onClick={() => {
                        /* <fs_premium_only> */
                        if (!pnpnm?.isPro) return;

                        onMenu("dynamic");
                        /* </fs_premium_only> */
                    }}
                />
            </Status>

            {/* <fs_premium_only> */}
            <div
                className={clsx(
                    "pnpnm-dynamic-folders__wrapper",
                    active &&
                        Object.keys(folders || {}).length > 0 &&
                        "pnpnm-dynamic-folders__wrapper--open",
                )}
            >
                <div
                    ref={scrollRef}
                    onScroll={checkFade}
                    className="pnpnm-dynamic-folders__container"
                >
                    <BlockStack
                        gap={5}
                        style={{
                            marginTop: 5,
                            paddingLeft: 10,
                        }}
                    >
                        {Object.entries(folders).map(([key, count]) => (
                            <Folder
                                key={key}
                                name={key}
                                count={showCount ? count : undefined}
                                icon={
                                    <ThemeIcon
                                        theme={theme}
                                        active={activeType === key}
                                        open={activeType === key}
                                    />
                                }
                                active={activeType === key}
                                open={activeType === key}
                                onClick={() => handleTypeClick(key)}
                            />
                        ))}
                    </BlockStack>
                </div>

                {showFade && <div className="pnpnm-dynamic-folders--fade" />}
            </div>
            {/* </fs_premium_only> */}
        </div>
    );
};

export default DynamicFolders;
