import { Folder, FolderContextMenu } from "~/types/folder";
import { useDeleteFolder } from "../actions/Delete";
import useMediaActions from "./useMediaActions";
import useMedia from "./useMedia";
/* <fs_premium_only> */
import { useDuplicateFolder } from "../actions/Duplicate__premium_only";
/* </fs_premium_only> */

type HandleFolderContextParams = {
    key: FolderContextMenu;
    folders: Folder[];
};

const useFolderContext = () => {
    const { setMedia, bulkSelect } = useMedia();

    const {
        moveFolder,
        /* <fs_premium_only> */
        downloadFolder,
        /* </fs_premium_only> */
    } = useMediaActions();

    /* <fs_premium_only> */
    const { openDuplicateFolder } = useDuplicateFolder();
    /* </fs_premium_only> */

    const { openDeleteFolder } = useDeleteFolder();

    const handleFolderContext = ({
        key,
        folders,
    }: HandleFolderContextParams) => {
        /* <fs_premium_only> */
        const ids = folders?.map((folder) => folder?.id) ?? [];
        /* </fs_premium_only> */
        const folder = folders?.[0];

        switch (key) {
            case "new":
                setMedia("activeFolder", folder);
                setMedia("createFolder", { create: true, folder });
                return;
            case "color":
                return;
            case "rename":
                setMedia("renameFolder", { rename: true, folder });
                return;
            case "cut":
                setMedia("cutFolders", { cut: true, folders });

                if (bulkSelect) {
                    setMedia("bulkSelect", false);
                    setMedia("selectedFolders", []);
                }
                return;
            case "paste":
                setMedia("moveFolder", { move: true, id: folder?.id });
                moveFolder({
                    target: folder?.id,
                });
                return;
            case "duplicate":
                /* <fs_premium_only> */
                if (!pnpnm?.isPro) return;

                openDuplicateFolder(
                    String(folder?.parentId),
                    String(folder?.id),
                );
                /* </fs_premium_only> */
                return;
            case "download":
                /* <fs_premium_only> */
                if (!pnpnm?.isPro) return;

                downloadFolder(ids);
                /* </fs_premium_only> */
                return;
            case "delete":
                openDeleteFolder(String(folder?.id));
                return;
            default: {
                const exhaustiveCheck: never = key;
                return exhaustiveCheck;
            }
        }
    };

    return handleFolderContext;
};

export default useFolderContext;
